15	function parseAgentCommand(message: string): AgentCommand | null {
16	  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
17	  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);
18	  
19	  if (commandMatch) {
20	    const [, command, target] = commandMatch;
21	    return {
22	      command: command as AgentCommand["command"],
23	      target: target?.trim(),
24	    };
25	  }
26	  
27	  return null;
28	}
